import React, { useState, useEffect } from 'react';
import axios from '../axios';
import { Link } from 'react-router-dom';
import { ThumbsUp, MessageCircle, Share2 } from 'lucide-react';
import './css/Post.css';

// Helper function to format date
const formatDate = (date) => {
    const now = new Date();
    const diff = now - new Date(date);
    const seconds = Math.floor(diff / 1000);
    const minutes = Math.floor(seconds / 60);
    const hours = Math.floor(minutes / 60);
    const days = Math.floor(hours / 24);

    if (days > 7) {
        return new Date(date).toLocaleDateString();
    } else if (days > 0) {
        return `${days} day${days > 1 ? 's' : ''} ago`;
    } else if (hours > 0) {
        return `${hours} hour${hours > 1 ? 's' : ''} ago`;
    } else if (minutes > 0) {
        return `${minutes} minute${minutes > 1 ? 's' : ''} ago`;
    } else {
        return 'Just now';
    }
};

const Post = ({ post, onDelete }) => {
    const [user, setUser] = useState({});
    const [likes, setLikes] = useState(post.likes.length);
    const [isLiked, setIsLiked] = useState(false);
    const [comments, setComments] = useState([]);
    const [newComment, setNewComment] = useState("");

    useEffect(() => {
        const fetchUser = async () => {
            try {
                const res = await axios.get(`/api/users/${post.userId}`);
                setUser(res.data);
            } catch (err) {
                console.error("Error fetching user:", err);
            }
        };
        fetchUser();
    }, [post.userId]);

    useEffect(() => {
        const fetchComments = async () => {
            try {
                const res = await axios.get(`/api/posts/${post._id}/comments`);
                setComments(res.data);
            } catch (err) {
                console.error("Error fetching comments:", err);
            }
        };
        fetchComments();
        // Check if the current user has liked the post
        const currentUser = JSON.parse(localStorage.getItem('user'));
        if (currentUser && post.likes) {
            setIsLiked(post.likes.includes(currentUser._id));
        }
    }, [post]);

    useEffect(() => {
        setLikes(post.likes.length);
    }, [post.likes]);

    const likeHandler = async () => {
        try {
            const currentUser = JSON.parse(localStorage.getItem('user'));
            if (!currentUser) {
                console.error("User not logged in");
                return;
            }
            await axios.put(`/api/posts/${post._id}/like`, { userId: currentUser._id });
            setLikes(isLiked ? likes - 1 : likes + 1);
            setIsLiked(!isLiked);
        } catch (err) {
            console.error("Error liking post:", err);
        }
    };

    const handleCommentSubmit = async (e) => {
        e.preventDefault();
        if (newComment.trim() === "") return;

        try {
            const currentUser = JSON.parse(localStorage.getItem('user'));
            if (!currentUser) {
                console.error("User not logged in");
                return;
            }
            const res = await axios.post(`/api/posts/${post._id}/comments`, {
                userId: currentUser._id,
                content: newComment
            });
            setComments([...comments, res.data]);
            setNewComment("");
        } catch (err) {
            console.error("Error posting comment:", err);
        }
    };

    return (
        <div className="post">
            <div className="post-wrapper">
                <div className="post-top">
                    <div className="post-top-left">
                        <Link to={`/profile/${user.username}`}>
                            <img
                                className="post-profile-img"
                                src={user.profilePicture || "/assets/person/noAvatar.png"}
                                alt=""
                            />
                        </Link>
                        <span className="post-username">{user.username}</span>
                        <span className="post-date">{formatDate(post.createdAt)}</span>
                    </div>
                    {post.userId === JSON.parse(localStorage.getItem('user'))?._id && (
                        <button onClick={() => onDelete(post._id)} className="delete-button">Delete</button>
                    )}
                </div>
                <div className="post-center">
                    <span className="post-text">{post.content}</span>
                    {post.img && <img className="post-img" src={post.img} alt="" />}
                </div>
                <div className="post-bottom">
                    <div className="post-bottom-left">
                        <ThumbsUp onClick={likeHandler} className={`like-icon ${isLiked ? 'liked' : ''}`} />
                        <span className="post-like-counter">{likes} likes</span>
                    </div>
                    <div className="post-bottom-right">
                        <MessageCircle className="comment-icon" />
                        <span className="post-comment-text">{comments.length} comments</span>
                        <Share2 className="share-icon" />
                    </div>
                </div>
                <form onSubmit={handleCommentSubmit} className="comment-form">
                    <input
                        type="text"
                        placeholder="Write a comment..."
                        className="comment-input"
                        value={newComment}
                        onChange={(e) => setNewComment(e.target.value)}
                    />
                    <button type="submit" className="comment-submit">Post</button>
                </form>
                <div className="comments-section">
                    {comments.map((comment) => (
                        <div key={comment._id} className="comment">
                            <span className="comment-username">{comment.username}: </span>
                            <span className="comment-content">{comment.content}</span>
                        </div>
                    ))}
                </div>
            </div>
        </div>
    );
};

export default Post;
